import React, { useState, useEffect, useCallback } from 'react';
import { Link } from 'react-router-dom';
import Navbar from '../components/Navbar';
import Sidebar from '../components/Sidebar';
import ProgressChart from '../components/ProgressChart';
import DailyTaskCard from '../components/DailyTaskCard';
import MissionTracker from '../components/MissionTracker';
import { useAuth } from '../context/AuthContext';
import { dashboardAPI } from '../services/api';

/* ── Stat Card ─────────────────────────────────────────────── */
function StatCard({ icon, label, value, sub, bg }) {
    return (
        <div className="card-hover card-shine flex flex-col gap-2 p-5">
            <div className={`w-11 h-11 rounded-2xl flex items-center justify-center text-xl ${bg}`}>
                {icon}
            </div>
            <p className="text-ink-400 text-xs font-medium">{label}</p>
            <p className="text-ink-900 text-2xl font-extrabold leading-none">{value}</p>
            {sub && <p className="text-ink-300 text-xs">{sub}</p>}
        </div>
    );
}

/* ── Quick action button ──────────────────────────────────── */
function QuickAction({ to, icon, label, bg }) {
    return (
        <Link
            to={to}
            className="card-hover p-4 flex flex-col items-center gap-2 text-center group"
        >
            <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-2xl ${bg}
                       group-hover:scale-110 transition-transform duration-200`}>
                {icon}
            </div>
            <span className="text-ink-500 text-xs font-semibold group-hover:text-ink-900 transition-colors">
                {label}
            </span>
        </Link>
    );
}

export default function Dashboard() {
    const { user, updateUser } = useAuth();
    const [sidebarOpen, setSidebarOpen] = useState(false);
    const [stats, setStats] = useState(null);
    const [tasks, setTasks] = useState([]);
    const [progress, setProgress] = useState(null);
    const [loading, setLoading] = useState(true);

    const fetchData = useCallback(async () => {
        try {
            const [statsRes, tasksRes, progressRes] = await Promise.allSettled([
                dashboardAPI.getStats(),
                dashboardAPI.getDailyTasks(),
                dashboardAPI.getProgress(),
            ]);
            if (statsRes.status === 'fulfilled') setStats(statsRes.value.data);
            if (tasksRes.status === 'fulfilled') setTasks(tasksRes.value.data?.tasks || []);
            if (progressRes.status === 'fulfilled') setProgress(progressRes.value.data);
        } catch {
            /* Use demo data silently */
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => { fetchData(); }, [fetchData]);

    const handleCompleteTask = async (taskId) => {
        try {
            const res = await dashboardAPI.completeTask(taskId);
            if (res.data?.xpEarned) {
                updateUser({ xp: (user?.xp || 0) + res.data.xpEarned });
            }
        } catch { /* ignore */ }
    };

    /* ── Demo stats if backend unavailable ─────────────────── */
    const displayStats = stats || {
        xp: user?.xp || 1250,
        level: user?.level || 3,
        rating: user?.rating || 78,
        sessions: 24,
        streak: 7,
        rank: '#42',
    };

    const xpToNext = 1000 - (displayStats.xp % 1000);
    const xpPercent = ((displayStats.xp % 1000) / 1000) * 100;

    const greetingHour = new Date().getHours();
    const greeting = greetingHour < 12 ? 'Good morning' : greetingHour < 18 ? 'Good afternoon' : 'Good evening';

    return (
        <div className="layout-root">
            <Sidebar open={sidebarOpen} onClose={() => setSidebarOpen(false)} />

            <div className="layout-main">
                <Navbar onMenuClick={() => setSidebarOpen(true)} />

                <main className="layout-content">
                    {/* ── Hero Greeting Banner ─────────────────── */}
                    <div className="card overflow-hidden"
                         style={{ background: 'linear-gradient(160deg, #FFF8E7 0%, #FFE5DC 50%, #EDE0F5 100%)' }}>
                        <div className="flex items-center justify-between flex-wrap gap-4">
                            <div className="flex-1 min-w-0">
                                <p className="text-ink-400 text-sm font-medium">{greeting},</p>
                                <h2 className="font-extrabold text-2xl text-ink-900 mt-0.5">
                                    {user?.name?.split(' ')[0] || 'Champion'} 👋
                                </h2>
                                <p className="text-ink-400 text-sm mt-1">
                                    Ready to level up your communication today?
                                </p>

                                {/* XP progress */}
                                <div className="mt-4 max-w-xs">
                                    <div className="flex justify-between text-xs mb-1.5">
                                        <span className="text-ink-500 font-medium">Level {displayStats.level}</span>
                                        <span className="text-orange-500 font-bold">{displayStats.xp} XP ⚡</span>
                                    </div>
                                    <div className="xp-bar-track animate-glow">
                                        <div className="xp-bar-fill animate-bar-fill" style={{ width: `${xpPercent}%` }} />
                                    </div>
                                    <p className="text-ink-300 text-xs mt-1">{xpToNext} XP to Level {displayStats.level + 1}</p>
                                </div>
                            </div>

                            {/* Streak badge */}
                            <div className="hidden sm:flex flex-col items-center gap-1 flex-shrink-0">
                                <div className="w-20 h-20 rounded-3xl flex flex-col items-center justify-center
                                    bg-white shadow-orange border-2 border-orange-200">
                                    <span className="text-orange-500 text-2xl font-extrabold">{displayStats.streak}</span>
                                    <span className="text-ink-400 text-[10px] font-medium">day streak</span>
                                </div>
                                <span className="text-orange-500 text-xs font-semibold">🔥 On fire!</span>
                            </div>
                        </div>
                    </div>

                    {/* ── Stat Cards ───────────────────────────── */}
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                        <StatCard icon="⭐" label="Rating Score"  value={displayStats.rating}         sub="out of 100"   bg="bg-orange-50" />
                        <StatCard icon="🎯" label="Sessions Done" value={displayStats.sessions}        sub="all time"     bg="bg-sky-100" />
                        <StatCard icon="🏆" label="Global Rank"   value={displayStats.rank}            sub="leaderboard"  bg="bg-mint-100" />
                        <StatCard icon="🔥" label="Day Streak"    value={`${displayStats.streak}d`}   sub="keep going!"  bg="bg-peach-100" />
                    </div>

                    {/* ── Quick Actions ────────────────────────── */}
                    <div>
                        <h3 className="section-title mb-3">🚀 Jump Back In</h3>
                        <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-6 gap-3">
                            <QuickAction to="/practice"    icon="🎤" label="Practice Speech"   bg="bg-orange-50" />
                            <QuickAction to="/interview"   icon="💼" label="Mock Interview"     bg="bg-sky-100" />
                            <QuickAction to="/gd"          icon="👥" label="Group Discussion"   bg="bg-mint-100" />
                            <QuickAction to="/learning"    icon="📚" label="Learning Hub"       bg="bg-lavender-100" />
                            <QuickAction to="/challenges"  icon="⚡" label="Challenges"         bg="bg-peach-100" />
                            <QuickAction to="/personality" icon="🧠" label="Personality"        bg="bg-purple-100" />
                        </div>
                    </div>

                    {/* ── Chart + Tasks + Missions ─────────────── */}
                    <div className="grid grid-cols-1 lg:grid-cols-5 gap-6">
                        <div className="lg:col-span-3 space-y-5">
                            <ProgressChart data={progress?.weekly} loading={loading} />
                            <MissionTracker />
                        </div>
                        <div className="lg:col-span-2">
                            <DailyTaskCard tasks={tasks} onComplete={handleCompleteTask} loading={loading} />
                        </div>
                    </div>
                </main>
            </div>
        </div>
    );
}
